122	interface ClaimPolicy {
123	  items: QuoteItem[];
124	}
125	
126	interface ClaimDamage {
127	  itemType: string;
128	  amount: number;
129	}
130	
131	interface ClaimIncident {
132	  cause: string;
133	  damages: ClaimDamage[];
134	}
135	
136	interface ClaimResult {
137	  payout: number;
138	  remainingCap: number;
139	}
140	
141	const DEDUCTIBLE = 100;
142	const CAP_MULTIPLIER = 2;
143	
144	const INSURANCE_VALUES: Record<string, number> = {
145	  sword: 1000,
146	  amulet: 600,
147	  staff: 800,
148	  potion: 400,
149	  rune: 250,
150	  moonstone: 250,
151	};
152	
153	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
154	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
155	
156	function isHighlyEnchanted(item: QuoteItem | undefined): boolean {
157	  return (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
158	}
159	
160	function insuredItemFor(damage: ClaimDamage, policy: ClaimPolicy): QuoteItem | undefined {
161	  return policy.items.find((item) => item.type === damage.itemType);
162	}
163	
164	function validateIncident(incident: ClaimIncident, policy: ClaimPolicy): void {
165	  const insuredCounts = countByType(policy.items);
166	  const damageCounts = tallyBy(incident.damages, (damage) => damage.itemType);
167	
168	  for (const [itemType, damageCount] of damageCounts) {
169	    if (damageCount > (insuredCounts.get(itemType) ?? 0)) {
170	      throw new Error(`Damage references more "${itemType}" items than the policy insures`);
171	    }
172	  }
173	}
174	
175	function reimbursementFor(damage: ClaimDamage, policy: ClaimPolicy): number {
176	  const insuredItem = insuredItemFor(damage, policy);
177	  if (isHighlyEnchanted(insuredItem)) {
178	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
179	  }
180	  return damage.amount;
181	}
182	
183	function payoutFor(incident: ClaimIncident, policy: ClaimPolicy): number {
184	  let payout = 0;
185	  for (const damage of incident.damages) {
186	    payout += reimbursementFor(damage, policy) - DEDUCTIBLE;
187	  }
188	  return payout;
189	}
190	
191	function capFor(policy: ClaimPolicy): number {
192	  let insuranceTotal = 0;
193	  for (const item of policy.items) {
194	    insuranceTotal += INSURANCE_VALUES[item.type];
195	  }
196	  return CAP_MULTIPLIER * insuranceTotal;
197	}
198	
199	export function claim(
200	  policy: ClaimPolicy,
201	  incident: ClaimIncident,
202	  remainingCap?: number,
203	): ClaimResult {
204	  validateIncident(incident, policy);
205	  const rawPayout = payoutFor(incident, policy);
206	  const availableCap = remainingCap ?? capFor(policy);
207	  const payout = Math.min(rawPayout, availableCap);
208	  return { payout, remainingCap: availableCap - payout };
209	}
